import { ServerError as ServerErrorComponent } from '@/checkout/components';
import { CheckoutError } from '@/checkout/data/models/checkout';
import { scrollToElement } from '@/checkout/lib/utils/dom';
import { Container } from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { useEffect, useRef, useState } from 'preact/hooks';

export interface ServerErrorProps {
  autoScroll?: boolean;
  onRetry?: (error: CheckoutError | null) => void;
  onServerError?: (error: string) => void;
  active?: boolean;
}

export const ServerError: Container<ServerErrorProps> = ({
  active = true,
  onRetry,
  onServerError,
  autoScroll = false,
}) => {
  const [error, setError] = useState<CheckoutError | null>(null);
  const errorMessageRef = useRef<HTMLParagraphElement>(null);

  const handleClick = async () => {
    onRetry?.(error);
    setError(null);
  };

  useEffect(() => {
    const subscription = events.on(
      'checkout/error',
      (error: CheckoutError | undefined) => {
        setError(error || null);
        if (error && onServerError) {
          onServerError(error.message);
        }
      },
      { eager: true }
    );

    return () => {
      subscription?.off();
    };
  }, [onServerError]);

  useEffect(() => {
    if (!autoScroll || !error || !errorMessageRef.current) return;
    scrollToElement(errorMessageRef.current);
  }, [error, autoScroll]);

  if (!active || !error) return null;

  return (
    <ServerErrorComponent
      errorMessage={error.message}
      errorMessageRef={errorMessageRef}
      onClick={handleClick}
    />
  );
};
